from __future__ import annotations

PAGE_STYLE = """:root{--bg:#eef0ea;--bg2:#e6e8e1;--panel:rgba(255,255,255,.8);--line:rgba(23,23,23,.12);--text:#171717;--muted:#636363;--shadow:0 24px 80px rgba(17,17,17,.08);--danger:#8b3030;--success:#2f6b44}body.dark{--bg:#111310;--bg2:#171916;--panel:rgba(35,38,33,.88);--line:rgba(255,255,255,.12);--text:#f3f3ee;--muted:#b4b7af;--shadow:0 24px 80px rgba(0,0,0,.28);--danger:#ffb6b1;--success:#b9e7c5}*{box-sizing:border-box}html,body{margin:0;min-height:100%}body{background:linear-gradient(180deg,var(--bg),var(--bg2));color:var(--text);font:16px/1.45 "Instrument Sans","Segoe UI",sans-serif}button,input,select,textarea,a,code{font:inherit}a{text-decoration:none}main{width:min(1080px,calc(100vw - 32px));margin:0 auto;padding:22px 0 48px}.topbar{display:flex;justify-content:space-between;align-items:center;gap:16px;margin-bottom:18px}.brand{display:inline-flex;align-items:center;gap:.7rem;font-size:.88rem;font-weight:700;letter-spacing:.08em;text-transform:uppercase}.brand-mark{width:.8rem;height:.8rem;border-radius:999px;background:currentColor}.top-controls,.actions{display:flex;align-items:center;gap:8px}.mini-control{display:inline-flex;align-items:center;justify-content:center;min-height:36px;padding:0 12px;border:1px solid var(--line);border-radius:999px;background:var(--panel);box-shadow:var(--shadow);color:var(--text);cursor:pointer}.session-chip{color:var(--muted);cursor:default}.theme-toggle svg{width:18px;height:18px;display:block}.stack{display:grid;gap:16px}.popup{border:1px solid var(--line);border-radius:30px;background:var(--panel);box-shadow:var(--shadow);overflow:hidden}.popup-inner{padding:22px}.hero-inner{padding:28px}.eyebrow{margin:0 0 .7rem;font-size:.76rem;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--muted)}h1,h2,p{margin:0}h1{font-size:clamp(2.3rem,6vw,3.8rem);line-height:.95;letter-spacing:-.06em}h2{font-size:1.35rem;line-height:1.05;letter-spacing:-.04em}.lead{margin-top:14px;max-width:42rem;color:var(--muted)}.lead.small{max-width:none}.pill-list{display:flex;flex-wrap:wrap;gap:.65rem;margin:1rem 0 0}.pill,.status-pill{padding:.58rem .8rem;border:1px solid var(--line);border-radius:999px;background:var(--panel);color:var(--muted);font-size:.9rem}.status-pill{white-space:nowrap}.actions{flex-wrap:wrap;margin-top:18px}.button{display:inline-flex;align-items:center;justify-content:center;min-height:42px;padding:0 16px;border:1px solid transparent;border-radius:999px;background:#fff;color:#171717;cursor:pointer}.secondary-button{background:transparent;border-color:var(--line);color:var(--text)}.button:disabled{opacity:.45;cursor:not-allowed}.message{margin-top:12px;min-height:1.4rem;color:var(--muted);font-size:.94rem}.message.is-error{color:var(--danger)}.shell{padding:16px;border:1px solid var(--line);border-radius:22px;background:var(--panel)}.field{display:grid;gap:8px}.field span,.chat-role{display:block;margin-bottom:.35rem;font-size:.72rem;letter-spacing:.08em;text-transform:uppercase;color:var(--muted)}.field span em{font-style:normal;opacity:.7;text-transform:none;letter-spacing:0}.field input,.field textarea{width:100%;padding:14px 16px;border:1px solid var(--line);border-radius:18px;background:var(--panel);color:var(--text);outline:none}.field textarea{min-height:118px;resize:vertical}.section-head{display:flex;justify-content:space-between;align-items:flex-start;gap:12px}.compact-head{margin-bottom:6px}.chat-log{display:grid;gap:12px;padding:18px;min-height:220px;max-height:520px;overflow-y:auto}.chat-form{display:grid;gap:12px;padding:18px;border-top:1px solid var(--line)}.chat-bubble{max-width:min(48rem,92%);padding:14px 16px;border:1px solid var(--line);border-radius:22px;background:var(--panel)}.chat-bubble.user{margin-left:auto;background:#fff;color:#171717}.chat-bubble.assistant{background:#fff;color:#171717}.chat-bubble.reasoning{color:var(--muted)}.reasoning-stack{display:flex;align-items:flex-end;min-height:calc(1.38em * 4);max-height:calc(1.38em * 4);overflow:hidden;-webkit-mask-image:linear-gradient(to top,rgba(0,0,0,1) 0%,rgba(0,0,0,.88) 28%,rgba(0,0,0,.66) 56%,rgba(0,0,0,.36) 78%,rgba(0,0,0,0) 100%);mask-image:linear-gradient(to top,rgba(0,0,0,1) 0%,rgba(0,0,0,.88) 28%,rgba(0,0,0,.66) 56%,rgba(0,0,0,.36) 78%,rgba(0,0,0,0) 100%)}.reasoning-text,.chat-content{width:100%;line-height:1.38;white-space:pre-wrap;word-break:break-word}.empty-state{padding:18px;border:1px dashed var(--line);border-radius:24px;color:var(--muted)}.admin-layout{display:grid;gap:14px;margin-top:18px}.admin-form,.admin-token-shell{padding:18px}.admin-grid{display:grid;gap:12px;grid-template-columns:repeat(2,minmax(0,1fr))}.admin-email-field{grid-column:1/-1}.token-row{display:flex;gap:10px;align-items:center;margin-top:14px}.token-link{display:block;flex:1;min-height:42px;padding:12px 14px;border:1px solid var(--line);border-radius:18px;background:var(--panel);color:var(--text);white-space:nowrap;overflow:auto}.table-shell{border:1px solid var(--line);border-radius:28px;background:var(--panel);overflow:hidden;margin-top:18px}table{width:100%;border-collapse:collapse}th,td{padding:16px 18px;text-align:left;border-bottom:1px solid var(--line);vertical-align:top}tr:last-child td{border-bottom:0}th{font-size:.74rem;letter-spacing:.08em;text-transform:uppercase;color:var(--muted);font-weight:600}.muted-cell{color:var(--muted)}.table-actions{display:flex;gap:8px;justify-content:flex-start;flex-wrap:wrap}.table-badge{display:inline-flex;align-items:center;min-height:32px;padding:0 10px;border:1px solid var(--line);border-radius:999px;color:var(--muted);white-space:nowrap}.table-badge.is-danger{color:var(--danger)}[hidden]{display:none !important}@media(max-width:640px){main{width:min(100vw - 20px,1080px)}.popup{border-radius:26px}.popup-inner,.hero-inner{padding:18px}.section-head{flex-direction:column}.table-shell{overflow-x:auto}.topbar{align-items:flex-start;flex-direction:column}.top-controls{flex-wrap:wrap}.admin-grid{grid-template-columns:1fr}.token-row{flex-direction:column;align-items:stretch}}"""
